mapper.update:
UPDATE t_car_cost_urea_pay
SET waybill_id = #{waybillId}
WHERE urea_pay_id = #{ureaPayId}

mapper.select:
SELECT ROUND(IFNULL(SUM(Amount), 0), 4)
FROM t_car_cost_urea_pay
WHERE waybill_id = #{waybillId} AND pay_mode = #{payMode} AND audit_status = #{auditStatus}

    AND oil_card_id = #{oilCardId}

SELECT
ccup.vehicle_id,
SUM(ccup.amount) amount
FROM t_car_cost_urea_pay ccup
LEFT JOIN t_waybill w ON w.waybill_id = ccup.waybill_id
where DATE_FORMAT(w.create_time, '%Y-%m-%d') >= #{queryForm.startTime}
AND DATE_FORMAT(w.create_time, '%Y-%m-%d') <= #{queryForm.endTime}
and ccup.enterprise_id = #{queryForm.enterpriseId}
and ccup.vehicle_id in

    #{item}

GROUP BY ccup.vehicle_id

SELECT ccup.*, cct.tabulation_id, cct.module_id, cct.module_type, w.waybill_number, w.container_number, v.vehicle_number, d.driver_name, ccc.cost_type, ccc.category_name FROM t_car_cost_tabulation cct LEFT JOIN t_waybill w ON cct.waybill_id = w.waybill_id LEFT JOIN t_vehicle v ON cct.vehicle_id = v.vehicle_id LEFT JOIN t_driver d ON cct.driver_id = d.driver_id LEFT JOIN t_car_cost_category ccc ON cct.category_id = ccc.category_id LEFT JOIN t_car_cost_urea_pay ccup ON cct.module_id = ccup.urea_pay_id
cct.tabulation_id IN
#{item}
